1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
